$ErrorActionPreference = "Stop"

$Root = Join-Path $env:USERPROFILE "Desktop\GPT_Prompts"
$Ready = Join-Path $Root "READY_TO_DROP_IN_CHAT"
$Current = Join-Path $Root "CURRENT"
$Custody = Join-Path $env:USERPROFILE "Desktop\123\GPT_PROMPTS_CUSTODY"
$ReceiptDir = Join-Path $Custody "RECEIPTS"
$ToolDir = Join-Path $Custody "TOOLS"
$Stamp = Get-Date -Format "yyyyMMdd_HHmmss"

New-Item -ItemType Directory -Path $Ready,$ReceiptDir,$ToolDir -Force | Out-Null

$MapBytes = [Convert]::FromBase64String("")
$LedgerBytes = [Convert]::FromBase64String("")
$VerifierBytes = [Convert]::FromBase64String("")

$MapPath = Join-Path $Ready "CHAT_SOFT_SUIT_MAP.md"
$LedgerPath = Join-Path $Ready "CHAT_SOFT_SUIT_IDEA_LEDGER.md"
$VerifierPath = Join-Path $ToolDir "VERIFY_CHAT_SOFT_SUIT_CURRENT_AUTHORITY_FIX.ps1"

[IO.File]::WriteAllBytes($MapPath, $MapBytes)
[IO.File]::WriteAllBytes($LedgerPath, $LedgerBytes)
[IO.File]::WriteAllBytes($VerifierPath, $VerifierBytes)

$ReadyMapHash = (Get-FileHash -Algorithm SHA256 -LiteralPath $MapPath).Hash
$ReadyLedgerHash = (Get-FileHash -Algorithm SHA256 -LiteralPath $LedgerPath).Hash
$VerifierHash = (Get-FileHash -Algorithm SHA256 -LiteralPath $VerifierPath).Hash

$CurrentMap = Join-Path $Current "CHAT_SOFT_SUIT_MAP.md"
$CurrentLedger = Join-Path $Current "CHAT_SOFT_SUIT_IDEA_LEDGER.md"
$CurrentMapHash = if (Test-Path -LiteralPath $CurrentMap) { (Get-FileHash -Algorithm SHA256 -LiteralPath $CurrentMap).Hash } else { "MISSING" }
$CurrentLedgerHash = if (Test-Path -LiteralPath $CurrentLedger) { (Get-FileHash -Algorithm SHA256 -LiteralPath $CurrentLedger).Hash } else { "MISSING" }

$ReadyMatchesCurrent = ($ReadyMapHash -eq $CurrentMapHash -and $ReadyLedgerHash -eq $CurrentLedgerHash)

$Receipt = Join-Path $ReceiptDir "CHAT_SOFT_SUIT_CURRENT_AUTHORITY_FIX_READY_ONLY_STANDALONE_$Stamp.txt"

@(
"CHAT SOFT SUIT CURRENT AUTHORITY FIX - READY ONLY STANDALONE",
"Timestamp: $Stamp",
"Root: $Root",
"Ready: $Ready",
"Current: $Current",
"ToolDir: $ToolDir",
"",
"Action: wrote corrected files to READY_TO_DROP_IN_CHAT only.",
"Action: wrote verifier tool to custody tools.",
"CURRENT touched by this script: NO",
"",
"Expected map SHA256: EB9215434C3773CC7F8ED40481C036055CDC30CCE7DEF328E32293FDF27A3F4F",
"Expected ledger SHA256: ABCE510EBB2A39FBDC42A89D6E7DB60435F7DFB2E993ECF5BDDEF3D11B50DE23",
"Ready map SHA256: $ReadyMapHash",
"Ready ledger SHA256: $ReadyLedgerHash",
"Verifier SHA256: $VerifierHash",
"Current map SHA256: $CurrentMapHash",
"Current ledger SHA256: $CurrentLedgerHash",
"READY matches CURRENT: $ReadyMatchesCurrent",
"",
"Locked correction:",
"- CURRENT is user-only.",
"- Assistant prepares READY.",
"- User moves accepted files into CURRENT.",
"- Assistant verifies CURRENT after user move.",
"- Move/sort authorization means cleanup/custody, not CURRENT promotion.",
"",
"Next user action if READY differs from CURRENT:",
"Move these files from READY_TO_DROP_IN_CHAT into CURRENT yourself:",
"- CHAT_SOFT_SUIT_MAP.md",
"- CHAT_SOFT_SUIT_IDEA_LEDGER.md",
"Then run verifier:",
"$VerifierPath",
"",
"Boundary: local-only; no Git; no public export; no doctrine promotion; no CURRENT write.",
"Verdict: $(if($ReadyMatchesCurrent){"PASS / CURRENT ALREADY HAS CORRECTED FILES"}else{"WAITING FOR USER / MOVE READY FILES INTO CURRENT THEN VERIFY"})"
) | Set-Content -LiteralPath $Receipt -Encoding UTF8

Get-Content -LiteralPath $Receipt -Raw
